#!/usr/bin/env python
"""Test specific regression scenario"""
import sys
sys.path.insert(0, '/workspace')
sys.path.insert(0, '/workspace/tests')

from django.template import Engine, Context
from django.conf import settings

if not settings.configured:
    settings.configure(
        DEBUG=True,
        DATABASES={
            'default': {
                'ENGINE': 'django.db.backends.sqlite3',
                'NAME': ':memory:',
            }
        },
        INSTALLED_APPS=[],
        TEMPLATES=[{
            'BACKEND': 'django.template.backends.django.DjangoTemplates',
            'DIRS': [],
            'APP_DIRS': False,
        }],
    )

import django
django.setup()

# Create a scenario where middle template's block content might leak through
templates = {
    "base.html": """
{% block outer %}
OUTER_BASE:{% block inner %}INNER_BASE{% endblock %}
{% endblock %}
""",
    "layout.html": """{% extends "base.html" %}
{% block outer %}
OUTER_LAYOUT:{% block inner %}INNER_LAYOUT{% endblock %}
{% endblock %}
""",
    "page.html": """{% extends "layout.html" %}
{% block inner %}INNER_PAGE{% endblock %}
""",
}

engine = Engine(
    loaders=[
        [
            'django.template.loaders.locmem.Loader',
            templates,
        ]
    ]
)

# Test the scenario
print("Test: Three-level inheritance with nested block override")
print("="*60)
template = engine.get_template("page.html")
output = template.render(Context({}))

print("Output:")
print(repr(output))
print("\nFormatted output:")
print(output)

# Check the content
has_outer_layout = 'OUTER_LAYOUT' in output
has_inner_page = 'INNER_PAGE' in output
has_inner_middle = 'INNER_LAYOUT' in output
has_inner_base = 'INNER_BASE' in output

print("\nAnalysis:")
print(f"  Has OUTER_LAYOUT: {has_outer_layout}")
print(f"  Has INNER_PAGE: {has_inner_page}")
print(f"  Has INNER_LAYOUT (leaked?): {has_inner_middle}")
print(f"  Has INNER_BASE: {has_inner_base}")

if has_outer_layout and has_inner_page and not has_inner_middle and not has_inner_base:
    print("\n✓ PASSED: Correct behavior")
else:
    print("\n✗ FAILED: Incorrect behavior")
    if has_inner_middle:
        print("  - BUG: Middle template's inner block leaked through!")

